import{_ as s,o as e,c as n,a2 as i}from"./chunks/framework.uqy4JyZe.js";const h=JSON.parse('{"title":"贡献指南","description":"","frontmatter":{"title":"贡献指南"},"headers":[],"relativePath":"contribution/index.md","filePath":"contribution/index.md","lastUpdated":null}'),l={name:"contribution/index.md"};function t(p,a,r,o,d,c){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="贡献指南" tabindex="-1">贡献指南 <a class="header-anchor" href="#贡献指南" aria-label="Permalink to &quot;贡献指南&quot;">​</a></h1><p>欢迎提交课程笔记、教程、历年真题、答案解析、实验资料和科研工具说明。本项目希望长期维护，因此更看重清晰、可读、可继续修改的内容。</p><h2 id="推荐贡献方式" tabindex="-1">推荐贡献方式 <a class="header-anchor" href="#推荐贡献方式" aria-label="Permalink to &quot;推荐贡献方式&quot;">​</a></h2><p>请优先提交 Markdown 文件。Markdown 页面可以直接通过 GitHub Pages 阅读，加载更快，也更容易被搜索、引用和修改。</p><p>PDF 仍然接受，适合以下情况：</p><ul><li>原始试卷扫描件</li><li>教师发布的正式讲义</li><li>暂时无法转换的复杂排版文件</li></ul><p>但 PDF 通常只能下载阅读，部分大陆网络环境下下载体验不如网页稳定。因此，如果你有能力整理成 Markdown，请优先提交 Markdown，并把 PDF 作为补充附件。</p><h2 id="文件放在哪里" tabindex="-1">文件放在哪里 <a class="header-anchor" href="#文件放在哪里" aria-label="Permalink to &quot;文件放在哪里&quot;">​</a></h2><ul><li>课程内容放在 <code>docs/courses/课程名/</code>。</li><li>历年真题放在 <code>docs/past-exams/课程名/</code>。</li><li>课堂讲义放在 <code>docs/lecture-notes/</code>。</li><li>科研工具教程放在 <code>docs/research-tools/</code>。</li></ul><h2 id="命名建议" tabindex="-1">命名建议 <a class="header-anchor" href="#命名建议" aria-label="Permalink to &quot;命名建议&quot;">​</a></h2><p>文件名请使用小写英文、数字和连字符，便于跨平台协作。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2025-final.md</span></span>
<span class="line"><span>2025-final.pdf</span></span>
<span class="line"><span>2025-final-solution.pdf</span></span>
<span class="line"><span>lagrangian.md</span></span>
<span class="line"><span>python-computing.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="真题页面如何自动生成下载入口" tabindex="-1">真题页面如何自动生成下载入口 <a class="header-anchor" href="#真题页面如何自动生成下载入口" aria-label="Permalink to &quot;真题页面如何自动生成下载入口&quot;">​</a></h2><p>如果 Markdown 与 PDF 放在同一目录，并且文件名前缀一致，网站会自动在页面底部显示下载按钮。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docs/past-exams/mechanics/2025-final.md</span></span>
<span class="line"><span>docs/past-exams/mechanics/2025-final.pdf</span></span>
<span class="line"><span>docs/past-exams/mechanics/2025-final-solution.pdf</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>上面的 Markdown 页面会自动关联两份 PDF。贡献者不需要手写下载按钮。</p><h2 id="markdown-写作建议" tabindex="-1">Markdown 写作建议 <a class="header-anchor" href="#markdown-写作建议" aria-label="Permalink to &quot;Markdown 写作建议&quot;">​</a></h2><ul><li>每个页面只写一个一级标题。</li><li>用二级标题组织主要内容。</li><li>公式使用 <code>$...$</code> 或 <code>$$...$$</code>。</li><li>代码块请标注语言。</li><li>图片放在相邻目录或 <code>docs/public/assets/</code> 中。</li><li>如果内容来自他人资料，请说明来源和授权情况。</li></ul><h2 id="提交-pull-request-前" tabindex="-1">提交 Pull Request 前 <a class="header-anchor" href="#提交-pull-request-前" aria-label="Permalink to &quot;提交 Pull Request 前&quot;">​</a></h2><p>本地运行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果只是新增 Markdown 或 PDF，自动脚本会刷新索引、侧边栏和下载列表。</p><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h2><p>如有问题，请邮件联系 <a href="mailto:betterfudan@outlook.com" target="_blank" rel="noreferrer">betterfudan@outlook.com</a>，或直接在 GitHub 上提交 Issue / Pull Request。</p>`,24)])])}const b=s(l,[["render",t]]);export{h as __pageData,b as default};
